// // This module selects between two 8-bit input buses, in0 and in1, based on a single-bit address signal. When the address is high (1), the output will be equal to in0; when the address is low (0), the output will be equal to in1.
module top_module(
    input address,
    input [7:0] in0,
    input [7:0] in1,
    output [7:0] out
    );assign out = (address == 1'b1) ? in1 : in0;

endmodule
